-- Table structure for withdrawal_of_balance
-- ----------------------------
DROP TABLE IF EXISTS `withdrawal_of_balance`;
CREATE TABLE `withdrawal_of_balance`  (
  `withdrawal_of_balance_id` int NOT NULL AUTO_INCREMENT COMMENT '余额提现ID',
  `account_number` varchar(64) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '账号编号',
  `account_balance` varchar(64) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '账户余额',
  `withdrawal_amount` int NULL DEFAULT 0 COMMENT '提现金额',
  `withdrawal_time` date NULL DEFAULT NULL COMMENT '提现时间',
  `withdrawal_bank_card` varchar(64) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '提现银行卡',
  `user_account` int NULL DEFAULT 0 COMMENT '用户账号',
  `recommend` int NOT NULL DEFAULT 0 COMMENT '智能推荐',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`withdrawal_of_balance_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 9 CHARACTER SET = utf8mb3 COLLATE = utf8mb3_general_ci COMMENT = '余额提现' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of withdrawal_of_balance
-- ----------------------------

SET FOREIGN_KEY_CHECKS = 1;
